import React, { useState } from "react";

// Screens
import HomeScreen from "./screens/HomeScreen";
import DepositScreen from "./screens/DepositScreen";
import WithdrawScreen from "./screens/WithdrawScreen";
import TransactionHistoryScreen from "./screens/TransactionHistoryScreen";
import TransactionReceiptScreen from "./screens/TransactionReceiptScreen";
import AddMoneyOptionsScreen from "./screens/AddMoneyOptionsScreen";
import PaymentProcessingScreen from "./screens/PaymentProcessingScreen";
import PaymentSuccessScreen from "./screens/PaymentSuccessScreen";


export default function App() {
  const [view, setView] = useState("home"); // main navigation
  const [balance, setBalance] = useState(5000);
  const [transactions, setTransactions] = useState([]);
  const [selectedTransaction, setSelectedTransaction] = useState(null);
  const [selectedOption, setSelectedOption] = useState(null);

  // Deposit handler
  const handleDeposit = (amount) => {
    const tx = {
      id: Date.now(),
      type: "Deposit",
      amount,
      date: new Date().toLocaleString(),
      reference: `DEP${Math.floor(Math.random() * 1000000)}`,
    };
    setTransactions([tx, ...transactions]);
    setBalance(balance + amount);
    setSelectedTransaction(tx);
    setView("paymentSuccess");
  };

  // Withdraw handler
  const handleWithdraw = (amount) => {
    const tx = {
      id: Date.now(),
      type: "Withdrawal",
      amount,
      date: new Date().toLocaleString(),
      reference: `WTH${Math.floor(Math.random() * 1000000)}`,
    };
    setTransactions([tx, ...transactions]);
    setBalance(balance - amount);
    setSelectedTransaction(tx);
    setView("receipt");
  };

  // Select transaction from history
  const handleSelectTransaction = (tx) => {
    setSelectedTransaction(tx);
    setView("receipt");
  };

  // Screen router
  switch (view) {
    case "deposit":
      return (
        <DepositScreen
          onDeposit={(amt) => setView("paymentProcessing") || setTimeout(() => handleDeposit(amt), 1500)}
          onBack={() => setView("home")}
        />
      );

    case "withdraw":
      return (
        <WithdrawScreen
          balance={balance}
          onWithdraw={handleWithdraw}
          onBack={() => setView("home")}
        />
      );

    case "history":
      return (
        <TransactionHistoryScreen
          transactions={transactions}
          onSelectTransaction={handleSelectTransaction}
          onBack={() => setView("home")}
        />
      );

    case "receipt":
      return (
        <TransactionReceiptScreen
          transaction={selectedTransaction}
          onBack={() => setView("home")}
        />
      );

    case "addMoneyOptions":
      return (
        <AddMoneyOptionsScreen
          onBack={() => setView("home")}
          onSelectOption={(opt) => {
            setSelectedOption(opt);
            setView("paymentProcessing");
            setTimeout(() => setView("paymentSuccess"), 1500);
          }}
        />
      );

    case "paymentProcessing":
      return (
        <PaymentProcessingScreen onBack={() => setView("home")} />
      );

    case "paymentSuccess":
      return (
        <PaymentSuccessScreen
          transaction={selectedTransaction || { amount: 0, reference: "N/A" }}
          onBack={() => setView("home")}
        />
      );

    default:
      // Home screen
      return (
        <HomeScreen
          balance={balance}
          onDeposit={() => setView("deposit")}
          onWithdraw={() => setView("withdraw")}
          onHistory={() => setView("history")}
          onAddMoneyOptions={() => setView("addMoneyOptions")}
        />
      );
  }
}
